// Config from previous node (Get Config) to avoid 'Referenced node doesn't exist'
const config = $input.first().json;
let input;
try {
  input = $('Execute Workflow Trigger').first().json;
} catch (e) {
  input = $('When executed by another node').first().json;
}

const priorityMap = {
  info: '\u2139\uFE0F',
  warning: '\u26A0\uFE0F',
  error: '\uD83D\uDEA8'
};

const priority = input.priority || 'info';
const emoji = priorityMap[priority] || priorityMap.info;
const rawMessage = input.message ?? input.text ?? '';
const msgText = (typeof rawMessage === 'string' ? rawMessage : String(rawMessage || '')).trim() || '(no message)';
const message = `${emoji} ${msgText}`;

return [{
  json: {
    webhookUrl: config.google.chatWebhookUrl,
    text: message
  }
}];

return [{
  json: {
    success: true,
    data: { sent: true },
    error: null
  }
}];
